<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ollama Chat</title>
    <link rel="stylesheet" href="{% static 'css/output.css' %}">
</head>
<body class="bg-gray-900 text-white min-h-screen flex flex-col">
    {% include "chat/header.html" %}

    <main class="flex-1 container mx-auto max-w-3xl px-4 py-6">
        <div id="chat-container" hx-ws="connect:/ws/chat/{{ session_id }}/">
            {% include "chat/message_list.html" %}
            {% include "chat/input_form.html" %}
        </div>
    </main>

    <script src="{% static 'js/htmx.min.js' %}"></script>
    <script>
        document.body.addEventListener('htmx:ws-message', function(evt) {
            const data = JSON.parse(evt.detail.message);
            if (data.error) {
                appendError(data.error);
            } else if (data.done) {
                finalizeMessage();
            } else if (data.token) {
                appendToken(data.token);
            }
        });

        function appendToken(token) {
            let assistantMsg = document.getElementById('assistant-stream');
            if (!assistantMsg) {
                assistantMsg = document.createElement('div');
                assistantMsg.id = 'assistant-stream';
                assistantMsg.className = 'bg-gray-800 rounded-xl p-4 mb-4 assistant-message';
                assistantMsg.textContent = '';
                document.getElementById('message-list').appendChild(assistantMsg);
            }
            assistantMsg.textContent += token;
            scrollToBottom();
        }

        function finalizeMessage() {
            const assistantMsg = document.getElementById('assistant-stream');
            if (assistantMsg) {
                assistantMsg.id = '';
                assistantMsg.className = 'bg-gray-800 rounded-xl p-4 mb-4 message assistant-message';
            }
            document.getElementById('message-input').disabled = false;
            document.getElementById('send-btn').disabled = false;
        }

        function appendError(error) {
            const errorMsg = document.createElement('div');
            errorMsg.className = 'bg-red-900 rounded-xl p-4 mb-4 text-red-300';
            errorMsg.textContent = 'Error: ' + error;
            document.getElementById('message-list').appendChild(errorMsg);
            document.getElementById('message-input').disabled = false;
            document.getElementById('send-btn').disabled = false;
            scrollToBottom();
        }

        function scrollToBottom() {
            const container = document.getElementById('message-list');
            container.scrollTop = container.scrollHeight;
        }

        document.getElementById('chat-form').addEventListener('htmx:beforeSend', function() {
            const input = document.getElementById('message-input');
            const message = input.value.trim();
            if (!message) {
                htmx.trigger(htmx.find('#chat-form'), 'htmx:abort');
                return;
            }
            addUserMessage(message);
            input.value = '';
            input.disabled = true;
            document.getElementById('send-btn').disabled = true;
        });

        function addUserMessage(message) {
            const userMsg = document.createElement('div');
            userMsg.className = 'bg-blue-600 rounded-xl p-4 mb-4 message user-message';
            userMsg.textContent = message;
            document.getElementById('message-list').appendChild(userMsg);
            scrollToBottom();
        }
    </script>
</body>
</html>

