class TestChatConsumer:
    def test_consumer_has_history_attribute(self):
        assert hasattr(ChatConsumer, "history")

    def test_history_initialized_empty(self):
        ChatConsumer.history.clear()
        assert ChatConsumer.history == {}

    def test_history_stores_session_messages(self):
        ChatConsumer.history.clear()
        ChatConsumer.history["test-session"] = [
            {"role": "user", "content": "Hello"},
            {"role": "assistant", "content": "Hi there!"},
        ]
        assert len(ChatConsumer.history["test-session"]) == 2
        assert ChatConsumer.history["test-session"][0]["role"] == "user"
        ChatConsumer.history.clear()


